  CHAR_UUID,
  BLECharacteristic::PROPERTY_READ |
  BLECharacteristic::PROPERTY_NOTIFY
);
pChar->addDescriptor(new BLE2902()); // OBBLIGATORIO per notify

// Inviare notifica nel loop:
if (deviceConnected) {
  uint32_t val = millis();
  pChar->setValue((uint8_t*)&val, 4);
  pChar->notify();
  delay(100); // non troppo veloce
}

bool deviceConnected = false;
class MyCallbacks: public BLEServerCallbacks {
  void onConnect(BLEServer* pServer) {
    deviceConnected = true;
  }
  void onDisconnect(BLEServer* pServer) {
    deviceConnected = false;
    delay(500); // lascia stabilizzare lo stack
    pServer->startAdvertising(); // riprende advertising
  }
};
// Nel setup:
pServer->setCallbacks(new MyCallbacks());

#include <BLEDevice.h>
#include <BLEScan.h>
#include <BLEAdvertisedDevice.h>
class MyCallbacks: public BLEAdvertisedDeviceCallbacks {
  void onResult(BLEAdvertisedDevice dev) {
    Serial.printf("Device: %s RSSI:%d\n",
      dev.getName().c_str(), dev.getRSSI());
  }
};
void setup() {
  BLEDevice::init("");
  BLEScan* scan = BLEDevice::getScan();
  scan->setAdvertisedDeviceCallbacks(new MyCallbacks());
  scan->setActiveScan(true);
  scan->start(5, false); // 5 secondi
  scan->clearResults();
}

class CharCallbacks: public BLECharacteristicCallbacks {
  void onWrite(BLECharacteristic *pChar) {
    std::string val = pChar->getValue();
    if (val.length() > 0) {
      Serial.print("Ricevuto: ");
      for (char c : val) Serial.print(c);
      Serial.println();
    }
  }
};
// Nel setup:
pChar->setCallbacks(new CharCallbacks());

// Confronto:
// WiFi TCP: router necessario, latenza 50ms+, pacchetti grandi, internet OK
// ESP-NOW: P2P diretto, latenza 1ms, max 250 byte/pacchetto, no internet
// Scelta: sensori → ESP-NOW; dashboard web → WiFi TCP

void loop() {
  if (WiFi.status() != WL_CONNECTED) {
    Serial.println("WiFi perso, riconnessione...");
    WiFi.reconnect();
    int tentativi = 0;
    while (WiFi.status() != WL_CONNECTED && tentativi < 10) {
      delay(500); tentativi++;
    }
    if (WiFi.status() == WL_CONNECTED)
      Serial.println("Riconnesso!");
  }
  // resto del codice...
  delay(1000);
}
